import{_ as n,b as t,e,al as l}from"./chunks/framework.DrQIcdFj.js";(function(){try{var s=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};s.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var i=new s.Error().stack;i&&(s._sentryDebugIds=s._sentryDebugIds||{},s._sentryDebugIds[i]="0af7c9e8-b7c0-4537-b4d1-b6001c90e5af",s._sentryDebugIdIdentifier="sentry-dbid-0af7c9e8-b7c0-4537-b4d1-b6001c90e5af")}catch{}})();const g=JSON.parse('{"title":"前端部署架构与多环境演进","description":"","frontmatter":{},"headers":[],"relativePath":"forntEngineering/ci-cd/deploymentEnvironments.md","filePath":"forntEngineering/ci-cd/deploymentEnvironments.md","lastUpdated":null}'),h={name:"forntEngineering/ci-cd/deploymentEnvironments.md"};function o(s,i,a,p,r,d){return t(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="前端部署架构与多环境演进" tabindex="-1">前端部署架构与多环境演进 <a class="header-anchor" href="#前端部署架构与多环境演进" aria-label="Permalink to &quot;前端部署架构与多环境演进&quot;">​</a></h1><p>在现代软件工程中，如果说 CI/CD 是运送代码的高速公路，那么“<strong>部署环境</strong>（Deployment Environments）”就是这条公路上的各个途经站与最终目的地。</p><p>早期前端开发往往只有“<strong>本地开发</strong>”和“<strong>线上生产</strong>”两个概念，代码写完直接通过 FTP 扔到服务器。这种极其脆弱的单轨模式，一旦发生 Bug 就是直接面向用户的灾难。现代前端架构通过建立严格的多环境隔离机制，构建了一套从“<strong>实验室</strong>”到“<strong>真实战场</strong>”的缓冲防御体系。</p><h2 id="_1-核心痛点与架构哲学" tabindex="-1">1. 核心痛点与架构哲学 <a class="header-anchor" href="#_1-核心痛点与架构哲学" aria-label="Permalink to &quot;1. 核心痛点与架构哲学&quot;">​</a></h2><p>为什么企业级应用必须划分极其严格的部署环境？这主要为了解决以下三大架构痛点：</p><ul><li><strong>数据与权限的隔离（Data Isolation）：</strong> 开发时需要随意造假数据（Mock）或进行破坏性测试。如果直连生产数据库，一条 <code>DELETE</code> 语句的失误将导致灾难性的后果。</li><li><strong>验证流的阻断（Validation Pipeline）：</strong> 代码的运作状态在开发者自己的 MacBook、在测试人员的 Windows 电脑、以及在最终用户的手机上可能完全不同。必须提供一个与线上 100% 对齐的“彩排场地”。</li><li><strong>爆炸半径的控制（Blast Radius）：</strong> 当新功能存在内存泄漏或致命逻辑缺陷时，多层级的环境能确保它在到达真正用户之前被拦截。</li></ul><blockquote><p><strong>架构师箴言：</strong> 优秀的部署环境设计，其终极目标是实现——<strong>“在本地犯错是常态，在测试环境犯错是演习，在生产环境犯错是不可能发生的意外。”</strong></p></blockquote><h2 id="_2-企业级标准化四层环境模型" tabindex="-1">2. 企业级标准化四层环境模型 <a class="header-anchor" href="#_2-企业级标准化四层环境模型" aria-label="Permalink to &quot;2. 企业级标准化四层环境模型&quot;">​</a></h2><p>在标准的大中型互联网企业中，前端代码从诞生到面向真实用户，通常需要经历四道严密的网关：</p><table tabindex="0"><thead><tr><th>环境层级</th><th>英文缩写</th><th>核心定位</th><th>数据来源</th><th>访问权限</th><th>稳定性容忍度</th></tr></thead><tbody><tr><td><strong>开发环境</strong></td><td><strong>DEV</strong> (Development)</td><td>工程师日常开发、联调接口的沙箱。</td><td>Mock 数据或独立且脏乱的开发库。</td><td>仅研发团队内网可见。</td><td>极低（随时可能崩溃重构）。</td></tr><tr><td><strong>测试环境</strong></td><td><strong>QA / TEST</strong></td><td>测试工程师（QA）执行系统测试与自动化测试的战场。</td><td>相对规范的测试数据库。</td><td>研发与测试团队。</td><td>中（保证核心主流程通常可走通）。</td></tr><tr><td><strong>预发/预上线</strong></td><td><strong>UAT / PRE</strong> (User Acceptance)</td><td>灰度上线前最后的“准生产”彩排，产品经理和业务方验收。</td><td><strong>线上真实数据库的脱敏只读副本，或直接连线上库。</strong></td><td>公司内网或特定白名单 IP。</td><td>极高（无限逼近真实线上环境）。</td></tr><tr><td><strong>生产环境</strong></td><td><strong>PROD</strong> (Production)</td><td>真实用户访问的最终环境。</td><td>线上真实商业数据库。</td><td>面向全网公网公开。</td><td><strong>绝对零容忍</strong>（可用性需达 99.99%）。</td></tr></tbody></table><h2 id="_3-环境隔离的底层基石-环境变量与构建注入" tabindex="-1">3. 环境隔离的底层基石：环境变量与构建注入 <a class="header-anchor" href="#_3-环境隔离的底层基石-环境变量与构建注入" aria-label="Permalink to &quot;3. 环境隔离的底层基石：环境变量与构建注入&quot;">​</a></h2><p>框架（Vue/React/Vite/Webpack）是如何知道代码当前正跑在哪个环境的？这完全依赖于现代前端构建工具链提供的<strong>编译期环境变量注入机制</strong>。它是前端工程化中连接本地开发与服务器部署的核心纽带。</p><h3 id="_3-1-跨环境网关-env-体系与安全防线" tabindex="-1">3.1 跨环境网关：<code>.env</code> 体系与安全防线 <a class="header-anchor" href="#_3-1-跨环境网关-env-体系与安全防线" aria-label="Permalink to &quot;3.1 跨环境网关：\`.env\` 体系与安全防线&quot;">​</a></h3><p>现代构建工具采用了一套优雅的“按需覆盖与回退”机制来加载环境配置。在一个标准的企业级项目中，<code>.env</code> 文件体系通常具备极其严密的层级结构：</p><ul><li><strong><code>.env</code></strong>：所有环境的通用默认配置（兜底基线）。</li><li><strong><code>.env.development</code></strong>：执行 <code>pnpm dev</code> 时被加载，专门用于本地联调，覆盖 <code>.env</code> 中的同名配置。</li><li><strong><code>.env.production</code></strong>：执行 <code>pnpm build</code> 时被默认加载，用于生产环境打包。</li><li><strong><code>.env.staging</code></strong>：预发环境专属，通过 <code>pnpm build --mode staging</code> 显式激活。</li><li><strong><code>.env.[mode].local</code></strong>：<strong>架构级隔离防线。</strong> 带有 <code>.local</code> 后缀的文件拥有最高加载优先级，且<strong>必须被加入 <code>.gitignore</code></strong>。它专供开发者在本地覆盖特定配置（例如临时将接口指向同事的本机 IP），而不必担心代码提交后污染全局团队环境。</li></ul><p><strong>核心机制：白名单前缀过滤策略</strong></p><p>在 Node.js 运行构建命令时，它可以读取系统内所有的环境变量（包括极度敏感的 <code>DB_PASSWORD</code> 或 <code>AWS_SECRET_KEY</code>）。为了防止构建工具将后端私钥“<strong>顺手</strong>”打包进前端公开的 JS 代码中，框架引入了强制的<strong>白名单安全机制</strong>。</p><p>只有显式带有特定前缀的变量才会被放行进入前端上下文：</p><ul><li><strong>Vite:</strong> 必须以 <code>VITE_</code> 开头（例如 <code>VITE_API_URL</code>）。</li><li><strong>Vue CLI:</strong> 必须以 <code>VUE_APP_</code> 开头。</li><li><strong>Create React App:</strong> 必须以 <code>REACT_APP_</code> 开头。</li></ul><p>不在白名单内的变量，在编译阶段会被前端引擎物理屏蔽，彻底杜绝机密泄露裸奔的可能。</p><h3 id="_3-2-前端环境隔离的特殊性-编译期定格-build-time-finality" tabindex="-1">3.2 前端环境隔离的特殊性：编译期定格 (Build-Time Finality) <a class="header-anchor" href="#_3-2-前端环境隔离的特殊性-编译期定格-build-time-finality" aria-label="Permalink to &quot;3.2 前端环境隔离的特殊性：编译期定格 (Build-Time Finality)&quot;">​</a></h3><p>与 Node.js 后端服务可以在运行时（Runtime）动态读取服务器操作系统的环境变量不同，前端的部署产物只是一堆纯静态的 HTML、CSS 和 JS 文件，它们运行在用户的本地浏览器（完全无状态的沙箱）里。</p><blockquote><p><strong>底层逻辑：</strong> 浏览器根本不认识 <code>process.env</code>，更无法读取服务器磁盘上的 <code>.env</code> 文件。前端的环境隔离，是在 CI/CD 流水线的打包阶段（Build-Time）通过代码替换完成的。</p></blockquote><p>当你针对 UAT（用户验收测试）环境执行打包时，构建引擎（Webpack 的 <code>DefinePlugin</code> 或 Vite 的 <code>esbuild define</code>）会启动一次极其暴力的“<strong>全量 AST 语法树扫描与替换</strong>”：</p><p><strong>你的源码：</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gateway</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.env.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">VITE_API_URL</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.env.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;development&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;当前处于开发模式&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>编译后的实际产物：</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 变量被物理替换为纯字符串常量</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gateway</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://uat-api.example.com&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;uat&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;development&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 这里变成 false，随后整段 if 会被 Tree-Shaking 算法直接作为死代码删除</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;当前处于开发模式&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>架构推演结论：</strong> 一旦打出 <code>dist</code> 包，它的环境归属就已经彻底“<strong>定死</strong>”。你无法把一个针对 UAT 环境打出来的包，直接扔到生产环境的服务器上运行，因为它的底层 API 接口地址在打包完成的那一瞬间，就已经变成了无法更改的静态字符串。</p><h3 id="_3-3-架构进阶视角-向-运行时动态注入-演进-runtime-injection" tabindex="-1">3.3 架构进阶视角：向“运行时动态注入”演进 (Runtime Injection) <a class="header-anchor" href="#_3-3-架构进阶视角-向-运行时动态注入-演进-runtime-injection" aria-label="Permalink to &quot;3.3 架构进阶视角：向“运行时动态注入”演进 (Runtime Injection)&quot;">​</a></h3><p>上述的“<strong>编译期定格</strong>”虽然简单易用，但在现代<strong>云原生与 Docker 容器化部署</strong>的大厂标准中，却暴露出一个致命缺陷：违背了 <strong>&quot;Build Once, Deploy Anywhere&quot;（一次构建，到处运行）</strong> 的黄金准则。</p><p>如果采用编译期打包，部署测试、预发、生产三个环境，流水线就必须运行三次 <code>pnpm build</code> 产出三个不同的 Docker 镜像。这不仅极大浪费了构建资源，而且无法保证测试环境跑通的产物与生产环境产物在底层二进制上绝对一致（重新打包可能引入由于 npm 依赖细微变化导致的幽灵 Bug）。</p><p><strong>终极解法：将静态替换转为真正的运行时挂载</strong></p><p>为了让同一个包可以在任何环境流通，资深架构师通常会剥离构建时的环境依赖：</p><ul><li><strong>改造源码读取方式：</strong> 业务代码不再读取编译期的 <code>import.meta.env</code>，而是去读取挂载在全局 <code>window</code> 上的配置对象（如 <code>window._APP_CONFIG_.API_URL</code>）。</li></ul><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/config.ts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> API_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> window._APP_CONFIG_.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">API_URL</span></span></code></pre></div><ul><li><strong>预留配置文件：</strong> 在项目的 <code>public/index.html</code> 的 <code>&lt;head&gt;</code> 中，引入一个外部静态配置脚本 <code>&lt;script src=&quot;/config.js&quot;&gt;&lt;/script&gt;</code>。流水线打包时，这个文件只是一个空壳。</li></ul><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/env-config.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><ul><li><strong>容器启动瞬间注入 (Entrypoint Magic)：</strong> 当运维通过 Kubernetes (K8s) 将 Docker 镜像部署到生产环境集群时，通过容器注入环境变量。镜像内部包含一个启动脚本（bash script），在 Nginx 启动提供服务前的那 0.1 秒内，读取 K8s 传进来的真实环境变量，动态生成那个 <code>/config.js</code> 文件。</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># docker-entrypoint.sh</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;window._APP_CONFIG_ = {&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/nginx/html/env-config.js</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;  API_URL: &#39;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">API_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&#39;&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/nginx/html/env-config.js</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;};&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/nginx/html/env-config.js</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动 Nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;daemon off;&quot;</span></span></code></pre></div><p><strong>架构收益：</strong> 你现在拥有了一个极其纯粹的、跨环境通用的 Docker 镜像。无论部署到任何集群，只需修改容器的启动参数，前端就能瞬间感知新环境，真正打通了高级云原生交付的最后一块拼图。</p><h2 id="_4-前端现代部署架构三剑客" tabindex="-1">4. 前端现代部署架构三剑客 <a class="header-anchor" href="#_4-前端现代部署架构三剑客" aria-label="Permalink to &quot;4. 前端现代部署架构三剑客&quot;">​</a></h2><p>如果说 Webpack/Vite 是前端代码的“<strong>加工厂</strong>”，那么 <strong>Nginx、Docker 与 CDN 就是现代前端部署架构的“三剑客”</strong>。它们分别解决了<strong>流量分发与代理</strong>、<strong>环境一致性</strong>以及<strong>全球加速</strong>的三大核心痛点。</p><h3 id="_4-1-nginx-前端流量的总网关-the-traffic-controller" tabindex="-1">4.1 Nginx：前端流量的总网关 (The Traffic Controller) <a class="header-anchor" href="#_4-1-nginx-前端流量的总网关-the-traffic-controller" aria-label="Permalink to &quot;4.1 Nginx：前端流量的总网关 (The Traffic Controller)&quot;">​</a></h3><p>Nginx 是一个高性能的 HTTP 和反向代理 Web 服务器。在前端架构中，它通常扮演着<strong>静态资源宿主</strong>和<strong>跨域请求网关</strong>的双重角色。</p><h4 id="_4-1-1-spa-静态资源托管与路由兜底" tabindex="-1">4.1.1 SPA 静态资源托管与路由兜底 <a class="header-anchor" href="#_4-1-1-spa-静态资源托管与路由兜底" aria-label="Permalink to &quot;4.1.1 SPA 静态资源托管与路由兜底&quot;">​</a></h4><p>现代 Vue/React 单页应用（SPA）打包后只有一堆 JS/CSS 和一个 <code>index.html</code>。 如果用户直接访问 <code>https://domain.com/user/profile</code>，Nginx 默认会去服务器磁盘找 <code>/user/profile</code> 文件夹，找不到就会报 404。</p><p><strong>Nginx 必须配置路由兜底机制（<code>try_files</code>）：</strong></p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">www.yourdomain.com;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    root </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/share/nginx/html; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 前端 dist 目录的绝对路径</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        index </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.html;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 🌟 核心魔法：按顺序查找文件。如果找不到 URL 对应的真实文件，</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 就强行把 index.html 返回给浏览器，把剩下的路由解析工作交还给 Vue-Router。</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        try_files </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$uri $uri/ /index.html;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="_4-1-2-核心职能二-反向代理与跨域终结者-reverse-proxy" tabindex="-1">4.1.2 核心职能二：反向代理与跨域终结者 (Reverse Proxy) <a class="header-anchor" href="#_4-1-2-核心职能二-反向代理与跨域终结者-reverse-proxy" aria-label="Permalink to &quot;4.1.2 核心职能二：反向代理与跨域终结者 (Reverse Proxy)&quot;">​</a></h4><p>前端在生产环境中，是没有 Vite 的 <code>proxy</code> 帮你跨域的。浏览器严格的同源策略会导致前端（<code>www.a.com</code>）无法直接请求后端（<code>api.b.com</code>）。</p><p><strong>架构解法：</strong> 利用 Nginx 作为中间人。浏览器把 API 请求发给前端同域的 Nginx，Nginx 再在内网把请求转发给后端真实的 Java/Node 服务器。<strong>服务器之间通信是没有跨域限制的。</strong></p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 拦截所有以 /api/ 开头的请求</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /api/ </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 转发到真实的后端微服务集群</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://backend-cluster:8080/;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 透传真实的客户端 IP 给后端，否则后端看到的都是 Nginx 的 IP</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span></code></pre></div><h4 id="_4-1-3-核心职能三-极致性能压榨-gzip-brotli" tabindex="-1">4.1.3 核心职能三：极致性能压榨 (Gzip / Brotli) <a class="header-anchor" href="#_4-1-3-核心职能三-极致性能压榨-gzip-brotli" aria-label="Permalink to &quot;4.1.3 核心职能三：极致性能压榨 (Gzip / Brotli)&quot;">​</a></h4><p>前端花大力气把 Bundle 减小了 100KB，不如 Nginx 开启一行压缩配置。</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    gzip </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    gzip_types </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text/plain application/javascript text/css application/json;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    gzip_min_length </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 小于 1KB 的文件不压缩（因为压缩本身也消耗 CPU）</span></span></code></pre></div><h3 id="_4-2-docker-绝对一致性的封印魔法-containerization" tabindex="-1">4.2 Docker：绝对一致性的封印魔法 (Containerization) <a class="header-anchor" href="#_4-2-docker-绝对一致性的封印魔法-containerization" aria-label="Permalink to &quot;4.2 Docker：绝对一致性的封印魔法 (Containerization)&quot;">​</a></h3><p>&quot;<strong>在我的电脑上明明没问题！</strong>&quot; —— 这是软件工程界最著名的甩锅名言。 操作系统的差异、Node.js 版本的不同、全局变量的污染，使得传统的部署像是在走钢丝。</p><h4 id="_4-2-1-什么是-docker" tabindex="-1">4.2.1 什么是 Docker？ <a class="header-anchor" href="#_4-2-1-什么是-docker" aria-label="Permalink to &quot;4.2.1 什么是 Docker？&quot;">​</a></h4><p>Docker 是一种操作系统层面的虚拟化技术（容器化）。如果说虚拟机（VM）是打包了整栋带地基的别墅，那 Docker 容器就是标准化、轻量级的集装箱。</p><ul><li><strong>镜像 (Image)：</strong> 它是只读的构建图纸，包含了运行前端应用所需的最小化操作系统环境（如 Alpine Linux）、Nginx 软件以及你的 <code>dist</code> 静态文件。</li><li><strong>容器 (Container)：</strong> 镜像是死的，容器是活的。容器就是镜像运行起来的实例，完全隔离运行。</li></ul><h4 id="_4-2-2-前端的多阶段构建-multi-stage-build" tabindex="-1">4.2.2 前端的多阶段构建 (Multi-stage Build) <a class="header-anchor" href="#_4-2-2-前端的多阶段构建-multi-stage-build" aria-label="Permalink to &quot;4.2.2 前端的多阶段构建 (Multi-stage Build)&quot;">​</a></h4><p>在 CI/CD 流水线中，我们最推荐的构建前端 Docker 镜像的方式是<strong>多阶段构建</strong>。 它的精髓在于：<strong>用一个拥有 Node 环境的“胖容器”来编译代码，然后把编译好的产物（<code>dist</code>）拿出来，塞进一个极其纯净、极小的 Nginx“瘦容器”中对外发布。</strong></p><p>创建 <code>Dockerfile</code>：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ================= 第一阶段：构建阶段 (Builder) =================</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node:18-alpine </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> builder</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /app</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 利用 Docker 缓存层优化安装速度</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> package.json pnpm-lock.yaml ./</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> npm install -g pnpm &amp;&amp; pnpm install --frozen-lockfile</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 拷贝全部源码并打包</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> . .</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pnpm run build</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ================= 第二阶段：生产阶段 (Production) =================</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 抛弃上一步庞大的 Node 环境和几百兆的 node_modules</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nginx:alpine</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 把你自己写的 nginx.conf 配置文件覆盖进去</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ./nginx.conf /etc/nginx/conf.d/default.conf</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 🌟 神来之笔：只把第一阶段打包出来的 dist 目录拷贝到 Nginx 目录下</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --from=builder /app/dist /usr/share/nginx/html</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 暴露 80 端口</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">EXPOSE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 80</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动 Nginx，并保持前台运行</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nginx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-g&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;daemon off;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>架构收益：</strong> 最终产出的镜像体积从 1GB+ 瞬间缩小到不足 20MB。启动极其迅速，极大地提升了 K8s 弹性扩缩容的速度。</p><h3 id="_4-3-cdn-对抗物理距离的终极武器-content-delivery-network" tabindex="-1">4.3 CDN：对抗物理距离的终极武器 (Content Delivery Network) <a class="header-anchor" href="#_4-3-cdn-对抗物理距离的终极武器-content-delivery-network" aria-label="Permalink to &quot;4.3 CDN：对抗物理距离的终极武器 (Content Delivery Network)&quot;">​</a></h3><p>前端架构师必须明白一个残酷的物理事实：光速是有限的，海底光缆是拥挤的。 如果你的服务器在杭州，无论你的代码写得多好，美国的真实用户访问你的页面，光是 TCP 三次握手的物理延迟就高达 200ms 以上。</p><h4 id="_4-3-1-cdn-的核心原理" tabindex="-1">4.3.1 CDN 的核心原理 <a class="header-anchor" href="#_4-3-1-cdn-的核心原理" aria-label="Permalink to &quot;4.3.1 CDN 的核心原理&quot;">​</a></h4><p>CDN（内容分发网络）是一组分布在全球各地的缓存代理服务器节点（边缘节点 Edge Nodes）。</p><ul><li><strong>首次请求 (Miss)：</strong> 北京的用户请求一张图片，北京的边缘节点发现自己没有，于是千里迢迢去杭州的<strong>源站服务器 (Origin Server)</strong> 拉取。拉取回来后，一方面返回给用户，另一方面<strong>缓存在自己本地</strong>。</li><li><strong>后续请求 (Hit)：</strong> 另一个北京的用户再请求同一张图片，边缘节点直接从内存/磁盘中把缓存的数据扔给用户。<strong>响应时间从 100ms 瞬间降至 5ms。</strong></li></ul><h4 id="_4-3-2-为什么前端静态资源必须上-cdn" tabindex="-1">4.3.2 为什么前端静态资源必须上 CDN？ <a class="header-anchor" href="#_4-3-2-为什么前端静态资源必须上-cdn" aria-label="Permalink to &quot;4.3.2 为什么前端静态资源必须上 CDN？&quot;">​</a></h4><ul><li><strong>降低源站压力：</strong> 如果 10 万人同时访问你的大促页面，如果没有 CDN，你的 Nginx 瞬间就会被带宽打挂。有了 CDN，99% 的静态资源请求被边缘节点挡住了，根本到不了你的服务器。</li><li><strong>突破浏览器并发限制：</strong> 浏览器对同一个域名的并发连接数有限制（通常为 6 个）。将图片、JS 等静态资源放到专用的 CDN 域名下（如 <code>cdn.yourdomain.com</code>），可以利用多域名突破并发瓶颈（此特性在 HTTP/2 普及后有所弱化，但在传统网络中依然有效）。</li></ul><h4 id="_4-3-3-cdn-缓存失效陷阱" tabindex="-1">4.3.3 CDN 缓存失效陷阱 <a class="header-anchor" href="#_4-3-3-cdn-缓存失效陷阱" aria-label="Permalink to &quot;4.3.3 CDN 缓存失效陷阱&quot;">​</a></h4><blockquote><p><strong>“为什么我发版了，用户看到的还是旧页面？”</strong></p></blockquote><p>如果把全站都挂在 CDN 上，极易引发强缓存灾难。 <strong>正确的前端 CDN 发布架构：</strong></p><ul><li><strong>对于打包带哈希值的文件（如 <code>main.1a2b3c.js</code>, <code>logo.8f7d.png</code>）：</strong> 配置 CDN 节点<strong>永久缓存</strong>。因为文件内容一变，哈希就变了，文件名也就变了，永远不用担心缓存过期问题。</li><li><strong>对于入口文件（<code>index.html</code>）：</strong> 绝对<strong>不能缓存在 CDN 上</strong>，或者必须配置极短的缓存时间（如 1 分钟），并使用强制协商缓存（<code>Cache-Control: no-cache</code>）。这样才能保证用户每次访问入口，拿到的一定是最新的资源索引。</li></ul><h2 id="_5-生产环境部署的高级防御策略" tabindex="-1">5. 生产环境部署的高级防御策略 <a class="header-anchor" href="#_5-生产环境部署的高级防御策略" aria-label="Permalink to &quot;5. 生产环境部署的高级防御策略&quot;">​</a></h2><p>对于动辄百万日活的应用，直接全量部署到 PROD 风险极高。架构师通常会采用以下发版策略：</p><h3 id="_5-1-蓝绿部署-blue-green-deployment" tabindex="-1">5.1 蓝绿部署 (Blue-Green Deployment) <a class="header-anchor" href="#_5-1-蓝绿部署-blue-green-deployment" aria-label="Permalink to &quot;5.1 蓝绿部署 (Blue-Green Deployment)&quot;">​</a></h3><ul><li><strong>机制：</strong> 线上同时存在两套完全对等的环境（Blue 和 Green）。假设当前用户访问的是 Blue。发版时，我们将新代码部署到休眠的 Green 环境，内部测试无误后，<strong>在负载均衡器（网关）层面瞬间切换流量入口，指向 Green</strong>。</li><li><strong>优势：</strong> 零停机时间（Zero-Downtime）。一旦发现新版有致命缺陷，1 秒钟即可将路由切回 Blue，实现瞬间回滚。</li></ul><h3 id="_5-2-灰度发布-金丝雀发布-canary-release" tabindex="-1">5.2 灰度发布 / 金丝雀发布 (Canary Release) <a class="header-anchor" href="#_5-2-灰度发布-金丝雀发布-canary-release" aria-label="Permalink to &quot;5.2 灰度发布 / 金丝雀发布 (Canary Release)&quot;">​</a></h3><ul><li><strong>机制：</strong> 不瞬间切换全量流量，而是先让 5% 的用户（或特定区域、特定白名单用户）访问到新版本（这批用户被称为探路的“<strong>金丝雀</strong>”）。</li><li><strong>优势：</strong> 在极小范围内观测错误日志和用户反馈。如果各项监控指标（性能、报错率）平稳，再逐步将流量扩大到 20%、50%，直至 100% 全量。</li></ul><h2 id="_6-常见问题-faq-与高级避坑指南" tabindex="-1">6. 常见问题 (FAQ) 与高级避坑指南 <a class="header-anchor" href="#_6-常见问题-faq-与高级避坑指南" aria-label="Permalink to &quot;6. 常见问题 (FAQ) 与高级避坑指南&quot;">​</a></h2><h3 id="_6-1-历史路由-history-mode-刷新报-404-的千古难题" tabindex="-1">6.1 历史路由 (History Mode) 刷新报 404 的千古难题 <a class="header-anchor" href="#_6-1-历史路由-history-mode-刷新报-404-的千古难题" aria-label="Permalink to &quot;6.1 历史路由 (History Mode) 刷新报 404 的千古难题&quot;">​</a></h3><ul><li><strong>现象：</strong> 在本地开发一切正常，部署到 Nginx 或 OSS 后，点击页面内链接跳转正常。但一旦在非根路径（如 <code>/user/profile</code>）按下键盘的 F5 刷新，直接返回 404 页面不存在。</li><li><strong>底层原因：</strong> 前端 SPA（单页应用）的历史路由是伪路由。浏览器去向服务器真实请求 <code>/user/profile</code> 的物理文件，而服务器的磁盘上根本没有这个目录，只有根目录下的一个 <code>index.html</code>。</li><li><strong>终极解法：</strong> 在 Nginx 配置中加入兜底重定向，告诉服务器：“如果你找不到用户请求的那个文件，别报 404，一律把 <code>index.html</code> 返回给浏览器，剩下的路由工作交给 JS 引擎接管”。</li></ul><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  root </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/share/nginx/html;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  index </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.html;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 🌟 解决 404 的核心配置</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  try_files </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$uri $uri/ /index.html;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_6-2-强缓存带来的-幽灵发版-灾难" tabindex="-1">6.2 强缓存带来的“幽灵发版”灾难 <a class="header-anchor" href="#_6-2-强缓存带来的-幽灵发版-灾难" aria-label="Permalink to &quot;6.2 强缓存带来的“幽灵发版”灾难&quot;">​</a></h3><ul><li><strong>现象：</strong> 昨天晚上刚部署了紧急修复 Bug 的新版本，但今天一大早客户依然在群里投诉 Bug 存在，检查发现他们浏览器里跑的还是旧版本的 JS 代码。</li><li><strong>底层原因：</strong> HTTP 的强缓存策略（<code>Cache-Control</code>）让浏览器自作聪明地使用了本地磁盘上缓存的旧文件，根本没去向服务器请求新文件。</li><li><strong>工程化解法：</strong><ul><li><strong>资产哈希化（Vite/Webpack 默认行为）：</strong> 保证打包出的 JS/CSS 文件名带有内容哈希（例如 <code>app.a3b4c9.js</code>）。代码一旦改变，文件名必然改变。</li><li><strong>绝对不缓存入口：</strong> 在 Nginx 或 CDN 层面，强制配置 <code>index.html</code> <strong>永不缓存</strong>（<code>Cache-Control: no-store</code>）。</li><li><strong>永久缓存静态资产：</strong> 对于带有哈希值的 JS/CSS/图片，设置<strong>长达一年的强缓存</strong>（<code>Cache-Control: max-age=31536000</code>）。 <em>(这样一旦有新版发布，浏览器请求新鲜的 index.html，里面引用的 JS 文件名变了，自然就会去下载全新的 JS 资源，完美解决缓存更新问题。)</em></li></ul></li></ul><h3 id="_6-3-跨环境的-cors-跨域痛点" tabindex="-1">6.3 跨环境的 CORS 跨域痛点 <a class="header-anchor" href="#_6-3-跨环境的-cors-跨域痛点" aria-label="Permalink to &quot;6.3 跨环境的 CORS 跨域痛点&quot;">​</a></h3><ul><li><strong>现象：</strong> DEV 环境因为有 Vite 的 <code>proxy</code> 代理一切正常，一上 PROD 环境，所有的 API 请求全部报 CORS 跨域拦截。</li><li><strong>架构解法：</strong> 永远不要指望在纯前端层面解决生产环境的跨域。必须在部署环境的同源 Nginx 反向代理层，或者后端网关（如 Spring Cloud Gateway / Kong）层面配置统一的 <code>Access-Control-Allow-Origin</code> 响应头，从根本上打通跨域限制。</li></ul>`,91)])])}const c=n(h,[["render",o]]);export{g as __pageData,c as default};
